async function compareDates() {
  const showroomCode = 'NANDI_TOYOTA';
  
  // 1. Get dates from DB
  const { data: deliveries, count } = await supabase
    .from('deliveries')
    .select('id, date, delivery_name')
    .eq('showroom_code', showroomCode)
    .order('date', { ascending: true });

  console.log(`DB Count: ${count}`);
  
  // 2. Parse User sheet dates
  const parseDate = (dStr: any) => {
    if (!dStr || typeof dStr !== 'string') return dStr;
    const trimmed = dStr.trim();
    const dmyMatch = trimmed.match(/^(\d{1,2})[\s\-\/](\d{1,2})[\s\-\/](\d{2,4})$/);
    if (dmyMatch) {
      const [_, d, m, y] = dmyMatch;
      const fullYear = y.length === 2 ? `20${y}` : y;
      return `${fullYear}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
    }
    return trimmed;
  };
  
  const rawSheetDates = sheetDatesList.split(',').map(d => d.trim()).filter(d => d && d.toLowerCase() !== 'date');
  console.log(`Sheet Dates Count: ${rawSheetDates.length}`);
  
  const parsedSheetDates = rawSheetDates.map(parseDate);
  
  // 3. Count frequencies
  const dbFreqs: Record<string, number> = {};
  deliveries?.forEach(d => {
      dbFreqs[d.date] = (dbFreqs[d.date] || 0) + 1;
  });
  
  const sheetFreqs: Record<string, number> = {};
  parsedSheetDates.forEach(d => {
      sheetFreqs[d] = (sheetFreqs[d] || 0) + 1;
  });
  
  console.log('\n--- Differences ---');
  let diffFound = false;
  for (const date in dbFreqs) {
      if (dbFreqs[date] !== sheetFreqs[date]) {
          console.log(`Date ${date}: DB has ${dbFreqs[date] || 0}, Sheet has ${sheetFreqs[date] || 0}`);
          diffFound = true;
          
          if (dbFreqs[date] > (sheetFreqs[date] || 0)) {
               console.log(`  -> Extra Record(s) for ${date}`);
               const extraRecords = deliveries?.filter(dl => dl.date === date);
               console.log(`  -> Names of records on this date:`, extraRecords?.map(r => r.delivery_name));
          }
      }
  }
}

compareDates();
